// SPDX-License-Identifier: (GPL-2.0-only OR BSD-2-Clause)
/* Copyright (C) 2018 Netronome Systems, Inc. */

#include <linux/rtnetlink.h>
#include <net/pkt_cls.h>
#include <net/pkt_sched.h>
#include <net/red.h>

#include "../nfpcore/nfp_cpp.h"
#include "../nfp_app.h"
#include "../nfp_main.h"
#include "../nfp_net.h"
#include "../nfp_port.h"
#include "main.h"

static bool nfp_abm_qdisc_is_red(struct nfp_qdisc *qdisc)
{
	return qdisc->type == NFP_QDISC_RED || qdisc->type == NFP_QDISC_GRED;
}

static bool nfp_abm_qdisc_child_valid(struct nfp_qdisc *qdisc, unsigned int id)
{
	return qdisc->children[id] &&
	       qdisc->children[id] != NFP_QDISC_UNTRACKED;
}

static void *nfp_abm_qdisc_tree_deref_slot(void __rcu **slot)
{
	return rtnl_dereference(*slot);
}

static void
nfp_abm_stats_propagate(struct nfp_alink_stats *parent,
			struct nfp_alink_stats *child)
{
	parent->tx_pkts		+= child->tx_pkts;
	parent->tx_bytes	+= child->tx_bytes;
	parent->backlog_pkts	+= child->backlog_pkts;
	parent->backlog_bytes	+= child->backlog_bytes;
	parent->overlimits	+= child->overlimits;
	parent->drops		+= child->drops;
}

static void
nfp_abm_stats_update_red(struct nfp_abm_link *alink, struct nfp_qdisc *qdisc,
			 unsigned int queue)
{
	struct nfp_cpp *cpp = alink->abm->app->cpp;
	unsigned int i;
	int err;

	if (!qdisc->offloaded)
		return;

	for (i = 0; i < qdisc->red.num_bands; i++) {
		err = nfp_abm_ctrl_read_q_stats(alink, i, queue,
						&qdisc->red.band[i].stats);
		if (err)
			nfp_err(cpp, "RED stats (%d, %d) read failed with error %d\n",
				i, queue, err);

		err = nfp_abm_ctrl_read_q_xstats(alink, i, queue,
						 &qdisc->red.band[i].xstats);
		if (err)
			nfp_err(cpp, "RED xstats (%d, %d) read failed with error %d\n",
				i, queue, err);
	}
}

static void
nfp_abm_stats_update_mq(struct nfp_abm_link *alink, struct nfp_qdisc *qdisc)
{
	unsigned int i;

	if (qdisc->type != NFP_QDISC_MQ)
		return;

	for (i = 0; i < alink->total_queues; i++)
		if (nfp_abm_qdisc_child_valid(qdisc, i))
			nfp_abm_stats_update_red(alink, qdisc->children[i], i);
}

static void __nfp_abm_stats_update(struct nfp_abm_link *alink, u64 time_now)
{
	alink->last_stats_update = time_now;
	if (alink->root_qdisc)
		nfp_abm_stats_update_mq(alink, alink->root_qdisc);
}

static void nfp_abm_stats_update(struct nfp_abm_link *alink)
{
	u64 now;

	/* Limit the frequency of updates - stats of non-leaf qdiscs are a sum
	 * of all their leafs, so we would read the same stat multiple times
	 * for every dump.
	 */
	now = ktime_get();
	if (now - alink->last_stats_update < NFP_ABM_STATS_REFRESH_IVAL)
		return;

	__nfp_abm_stats_update(alink, now);
}

static void
nfp_abm_qdisc_unlink_children(struct nfp_qdisc *qdisc,
			      unsigned int start, unsigned int end)
{
	unsigned int i;

	for (i = start; i < end; i++)
		if (nfp_abm_qdisc_child_valid(qdisc, i)) {
			qdisc->children[i]->use_cnt--;
			qdisc->children[i] = NULL;
		}
}

static void
nfp_abm_qdisc_offload_stop(struct nfp_abm_link *alink, struct nfp_qdisc *qdisc)
{
	unsigned int i;

	/* Don't complain when qdisc is getting unlinked */
	if (qdisc->use_cnt)
		nfp_warn(alink->abm->app->cpp, "Offload of '%08x' stopped\n",
			 qdisc->handle);

	if (!nfp_abm_qdisc_is_red(qdisc))
		return;

	for (i = 0; i < qdisc->red.num_bands; i++) {
		qdisc->red.band[i].stats.backlog_pkts = 0;
		qdisc->red.band[i].stats.backlog_bytes = 0;
	}
}

static int
__nfp_abm_stats_init(struct nfp_abm_link *alink, unsigned int band,
		     unsigned int queue, struct nfp_alink_stats *prev_stats,
		     struct nfp_alink_xstats *prev_xstats)
{
	u64 backlog_pkts, backlog_bytes;
	int err;

	/* Don't touch the backlog, backlog can only be reset after it has
	 * been reported back to the tc qdisc stats.
	 */
	backlog_pkts = prev_stats->backlog_pkts;
	backlog_bytes = prev_stats->backlog_bytes;

	err = nfp_abm_ctrl_read_q_stats(alink, band, queue, prev_stats);
	if (err) {
		nfp_err(alink->abm->app->cpp,
			"RED stats init (%d, %d) failed with error %d\n",
			band, queue, err);
		return err;
	}

	err = nfp_abm_ctrl_read_q_xstats(alink, band, queue, prev_xstats);
	if (err) {
		nfp_err(alink->abm->app->cpp,
			"RED xstats init (%d, %d) failed with error %d\n",
			band, queue, err);
		return err;
	}

	prev_stats->backlog_pkts = backlog_pkts;
	prev_stats->backlog_bytes = backlog_bytes;
	return 0;
}

static int
nfp_abm_stats_init(struct nfp_abm_link *alink, struct nfp_qdisc *qdisc,
		   unsigned int queue)
{
	unsigned int i;
	int err;

	for (i = 0; i < qdisc->red.num_bands; i++) {
		err = __nfp_abm_stats_init(alink, i, queue,
					   &qdisc->red.band[i].prev_stats,
					   &qdisc->red.band[i].prev_xstats);
		if (err)
			return err;
	}

	return 0;
}

static void
nfp_abm_offload_compile_red(struct nfp_abm_link *alink, struct nfp_qdisc *qdisc,
			    unsigned int queue)
{
	bool good_red, good_gred;
	unsigned int i;

	good_red = qdisc->type == NFP_QDISC_RED &&
		   qdisc->params_ok &&
		   qdisc->use_cnt == 1 &&
		   !alink->has_prio &&

content.content:
   200→		   !alink->has_prio &&
   201→		   !qdisc->children[0];
   202→	good_gred = qdisc->type == NFP_QDISC_GRED &&
   203→		    qdisc->params_ok &&
   204→		    qdisc->use_cnt == 1;
   205→	qdisc->offload_mark = good_red || good_gred;
   206→
   207→	/* If we are starting offload init prev_stats */
   208→	if (qdisc->offload_mark && !qdisc->offloaded)
   209→		if (nfp_abm_stats_init(alink, qdisc, queue))
   210→			qdisc->offload_mark = false;
   211→
   212→	if (!qdisc->offload_mark)
   213→		return;
   214→
   215→	for (i = 0; i < alink->abm->num_bands; i++) {
   216→		enum nfp_abm_q_action act;
   217→
   218→		nfp_abm_ctrl_set_q_lvl(alink, i, queue,
   219→				       qdisc->red.band[i].threshold);
   220→		act = qdisc->red.band[i].ecn ?
   221→			NFP_ABM_ACT_MARK_DROP : NFP_ABM_ACT_DROP;
   222→		nfp_abm_ctrl_set_q_act(alink, i, queue, act);
   223→	}
   224→}
   225→
   226→static void
   227→nfp_abm_offload_compile_mq(struct nfp_abm_link *alink, struct nfp_qdisc *qdisc)
   228→{
   229→	unsigned int i;
   230→
   231→	qdisc->offload_mark = qdisc->type == NFP_QDISC_MQ;
   232→	if (!qdisc->offload_mark)
   233→		return;
   234→
   235→	for (i = 0; i < alink->total_queues; i++) {
   236→		struct nfp_qdisc *child = qdisc->children[i];
   237→
   238→		if (!nfp_abm_qdisc_child_valid(qdisc, i))
   239→			continue;
   240→
   241→		nfp_abm_offload_compile_red(alink, child, i);
   242→	}
   243→}
   244→
   245→void nfp_abm_qdisc_offload_update(struct nfp_abm_link *alink)
   246→{
   247→	struct nfp_abm *abm = alink->abm;
   248→	struct radix_tree_iter iter;
   249→	struct nfp_qdisc *qdisc;
   250→	void __rcu **slot;
   251→	size_t i;
   252→
   253→	/* Mark all thresholds as unconfigured */
   254→	for (i = 0; i < abm->num_bands; i++)
   255→		__bitmap_set(abm->threshold_undef,
   256→			     i * NFP_NET_MAX_RX_RINGS + alink->queue_base,
   257→			     alink->total_queues);
   258→
   259→	/* Clear offload marks */
   260→	radix_tree_for_each_slot(slot, &alink->qdiscs, &iter, 0) {
   261→		qdisc = nfp_abm_qdisc_tree_deref_slot(slot);
   262→		qdisc->offload_mark = false;
   263→	}
   264→
   265→	if (alink->root_qdisc)
   266→		nfp_abm_offload_compile_mq(alink, alink->root_qdisc);
   267→
   268→	/* Refresh offload status */
   269→	radix_tree_for_each_slot(slot, &alink->qdiscs, &iter, 0) {
   270→		qdisc = nfp_abm_qdisc_tree_deref_slot(slot);
   271→		if (!qdisc->offload_mark && qdisc->offloaded)
   272→			nfp_abm_qdisc_offload_stop(alink, qdisc);
   273→		qdisc->offloaded = qdisc->offload_mark;
   274→	}
   275→
   276→	/* Reset the unconfigured thresholds */
   277→	for (i = 0; i < abm->num_thresholds; i++)
   278→		if (test_bit(i, abm->threshold_undef))
   279→			__nfp_abm_ctrl_set_q_lvl(abm, i, NFP_ABM_LVL_INFINITY);
   280→
   281→	__nfp_abm_stats_update(alink, ktime_get());
   282→}
   283→
   284→static void
   285→nfp_abm_qdisc_clear_mq(struct net_device *netdev, struct nfp_abm_link *alink,
   286→		       struct nfp_qdisc *qdisc)
   287→{
   288→	struct radix_tree_iter iter;
   289→	unsigned int mq_refs = 0;
   290→	void __rcu **slot;
   291→
   292→	if (!qdisc->use_cnt)
   293→		return;
   294→	/* MQ doesn't notify well on destruction, we need special handling of
   295→	 * MQ's children.
   296→	 */
   297→	if (qdisc->type == NFP_QDISC_MQ &&
   298→	    qdisc == alink->root_qdisc &&
   299→	    netdev->reg_state == NETREG_UNREGISTERING)
   300→		return;
   301→
   302→	/* Count refs held by MQ instances and clear pointers */
   303→	radix_tree_for_each_slot(slot, &alink->qdiscs, &iter, 0) {
   304→		struct nfp_qdisc *mq = nfp_abm_qdisc_tree_deref_slot(slot);
   305→		unsigned int i;
   306→
   307→		if (mq->type != NFP_QDISC_MQ || mq->netdev != netdev)
   308→			continue;
   309→		for (i = 0; i < mq->num_children; i++)
   310→			if (mq->children[i] == qdisc) {
   311→				mq->children[i] = NULL;
   312→				mq_refs++;
   313→			}
   314→	}
   315→
   316→	WARN(qdisc->use_cnt != mq_refs, "non-zero qdisc use count: %d (- %d)\n",
   317→	     qdisc->use_cnt, mq_refs);
   318→}
   319→
   320→static void
   321→nfp_abm_qdisc_free(struct net_device *netdev, struct nfp_abm_link *alink,
